```class Solution {
    public int numberOfStableArrays(int zero, int one, int limit) {
        int MOD = 1000000007;
        long res = 1;
        for (int i = 1; i <= limit; i++) {
            res = res * (i - zero) % MOD * (i - one) % MOD;
        }
        return (int) res;
    }
}```
